// ════════════════════════════════════════════════════════════════
// CONFIGURACIÓN — único lugar que tocas para otra temporada
// ════════════════════════════════════════════════════════════════
const config = {
  // Formato con barra — igual que en tu DB
  season_label: '2020/21',

  // Slug de la competition en tu DB
  competition_slug: 'laliga-ea-sports',

  // Wikipedia: título de la temporada (sin https://en.wikipedia.org/wiki/)
  // Patrón: YYYY–YY_La_Liga  (guión largo Unicode en el año)
  wiki_season_title: '2020%E2%80%9321_La_Liga',

  // Transfermarkt
  transfermarkt_competition_code: 'ES1', // LaLiga
  total_matchdays: 38,
};

// ════════════════════════════════════════════════════════════════
// DERIVADOS AUTOMÁTICOS — no tocar
// ════════════════════════════════════════════════════════════════
const seasonCompact = config.season_label.replace('/', ''); // '202021'
const seasonSlug = `laliga-${config.season_label.replace('/', '-')}`; // 'laliga-2020-21'
const wikiUrl = `https://en.wikipedia.org/wiki/${config.wiki_season_title}`;

// Para Transfermarkt, 2020/21 => saison_id=2020
const seasonStartYear = parseInt(config.season_label.split('/')[0], 10);

const transfermarkt_base_url =
  `https://www.transfermarkt.es/laliga/spieltag/wettbewerb/${config.transfermarkt_competition_code}`;

return [{
  json: {
    ...config,

    // Wikipedia
    season_compact: seasonCompact,
    season_slug: seasonSlug,
    wiki_url: wikiUrl,

    // Transfermarkt
    transfermarkt_saison_id: seasonStartYear,
    transfermarkt_base_url,
  }
}];

// Lee todas las competitions y filtra en JS
// Así evitamos el problema de referencias cross-branch en Supabase nodes
const ctx = $('Set Contexto').first().json;

// El nodo Supabase 'Load Competition DB' cargará todas las competitions
// Este nodo solo prepara y pasa el contexto
return [{ json: { ...ctx } }];

// Leer del input directo en lugar de referenciar Set Contexto por nombre
const ctx = $('Set Contexto').first().json;
const allComps = $('Load Competition DB').all().map(i => i.json);

const competition = allComps.find(c => c.slug === ctx.competition_slug);

if (!competition) {
  throw new Error(`Competition no encontrada: "${ctx.competition_slug}"`);
}

return [{
  json: {
    ...ctx,
    competition_id:   competition.id,
    competition_name: competition.name,
  }
}];

// Ahora tenemos competition_id en $json y todas las seasons en Load CompSeason DB
const ctx         = $('Load Competition Season').first().json;
const allSeasons  = $('Load CompSeason DB').all().map(i => i.json);

// Buscar la season correcta: mismo competition_id y season_label
const existing = allSeasons.find(s =>
  s.competition_id === ctx.competition_id &&
  s.season_label   === ctx.season_label
);

if (existing) {
  // Ya existe
  return [{
    json: {
      ...ctx,
      competition_season_id: existing.id,
      _cs_created: false,
    }
  }];
}

// No existe — señal para crear
return [{
  json: {
    ...ctx,
    competition_season_id: null,
    _cs_created: true,
    _cs_insert: {
      competition_id: ctx.competition_id,
      season_label:   ctx.season_label,
      is_current:     false,
      source:         'wikipedia',
    }
  }
}];

const item = $input.first().json;
const ctx  = $('Set Contexto').first().json;  // fuente garantizada de wiki_url

const csId = item.id || item.competition_season_id;
if (!csId) {
  throw new Error('No se pudo obtener competition_season_id');
}

return [{
  json: {
    competition_id:         item.competition_id        || ctx.competition_id,
    competition_season_id:  csId,
    season_label:           item.season_label          || ctx.season_label,
    competition_slug:       item.competition_slug      || ctx.competition_slug,
    season_compact:         item.season_compact        || ctx.season_compact,
    season_slug:            item.season_slug           || ctx.season_slug,
    wiki_url:               ctx.wiki_url,
    competition_name:       item.competition_name,
  }
}];

const inputItems = $input.all();

const teams = $('Load Teams').all().map(x => x.json);
const aliases = $('Load Aliases').all().map(x => x.json);

function normalize(s) {
  return (s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

const teamMap = new Map();
for (const t of teams) {
  const candidates = [
    t.name,
    t.team_name,
    t.display_name,
    t.slug,
    t.short_name
  ].filter(Boolean);

  for (const c of candidates) {
    const key = normalize(c);
    if (key && !teamMap.has(key)) {
      teamMap.set(key, t);
    }
  }
}

const aliasMap = new Map();
for (const a of aliases) {
  const aliasRaw =
    a.alias ||
    a.alias_name ||
    a.name ||
    a.team_alias ||
    null;

  const aliasKey = normalize(aliasRaw);
  if (!aliasKey) continue;

  // intentar encontrar team_id directo
  const teamId =
    a.team_id ||
    a.canonical_team_id ||
    a.target_team_id ||
    null;

  if (teamId) {
    aliasMap.set(aliasKey, { team_id: teamId });
    continue;
  }

  // si el alias apunta a un nombre canónico
  const canonicalName =
    a.canonical_name ||
    a.team_name ||
    a.target_team_name ||
    null;

  if (canonicalName) {
    aliasMap.set(aliasKey, { canonical_name: canonicalName });
  }
}

function resolveTeam(rawName) {
  const key = normalize(rawName);
  if (!key) return null;

  // 1) match directo
  if (teamMap.has(key)) {
    return teamMap.get(key);
  }

  // 2) alias -> team_id o canonical_name
  if (aliasMap.has(key)) {
    const aliasData = aliasMap.get(key);

    if (aliasData.team_id) {
      const found = teams.find(t =>
        t.id === aliasData.team_id ||
        t.team_id === aliasData.team_id
      );
      if (found) return found;
    }

    if (aliasData.canonical_name) {
      const canonKey = normalize(aliasData.canonical_name);
      if (teamMap.has(canonKey)) {
        return teamMap.get(canonKey);
      }
    }
  }

  // 3) fuzzy básico: contains
  for (const [k, t] of teamMap.entries()) {
    if (k === key) return t;
    if (k.includes(key) || key.includes(k)) return t;
  }

  return null;
}

const out = [];
const errors = [];
const seen = new Set();

for (const inputItem of inputItems) {
  const m = inputItem.json || {};

  if (m.error) {
    errors.push({
      type: 'upstream_error',
      detail: m
    });
    continue;
  }

  const homeResolved = resolveTeam(m.home_team_raw);
  const awayResolved = resolveTeam(m.away_team_raw);

  const homeTeamId =
    homeResolved?.id ??
    homeResolved?.team_id ??
    null;

  const awayTeamId =
    awayResolved?.id ??
    awayResolved?.team_id ??
    null;

  const sourceId = m.source_id || null;

  if (!sourceId) {
    errors.push({
      type: 'missing_source_id',
      match: m
    });
    continue;
  }

  if (seen.has(sourceId)) {
    errors.push({
      type: 'duplicate_source_id',
      source_id: sourceId,
      match: m
    });
    continue;
  }
  seen.add(sourceId);

  if (!homeTeamId || !awayTeamId) {
    errors.push({
      type: 'unresolved_team',
      source_id: sourceId,
      home_team_raw: m.home_team_raw,
      away_team_raw: m.away_team_raw,
      resolved_home: homeResolved?.name || homeResolved?.team_name || null,
      resolved_away: awayResolved?.name || awayResolved?.team_name || null
    });
    continue;
  }

  out.push({
    json: {
      competition_id: m.competition_id ?? null,
      competition_season_id: m.competition_season_id ?? null,
      home_team_id: homeTeamId,
      away_team_id: awayTeamId,
      home_team_raw: m.home_team_raw ?? null,
      away_team_raw: m.away_team_raw ?? null,
      match_date: m.match_date ?? null,
      home_score: m.home_score ?? null,
      away_score: m.away_score ?? null,
      status: m.status ?? 'finished',
      stage: m.stage ?? 'league',
      source: m.source ?? 'wikipedia',
      source_id: sourceId,
      season: m.season ?? null,
      season_slug: m.season_slug ?? null
    }
  });
}

const summary = {
  total_input: inputItems.length,
  total_ok: out.length,
  total_errors: errors.length,
  unresolved_count: errors.filter(e => e.type === 'unresolved_team').length,
  duplicate_count: errors.filter(e => e.type === 'duplicate_source_id').length
};

// si quieres cortar duro cuando no esté perfecto
if (errors.length > 0) {
  return [{
    json: {
      error: 'validation_failed',
      summary,
      errors: errors.slice(0, 100)
    }
  }];
}

// si quieres además validar 380 exactos
if (out.length !== 380) {
  return [{
    json: {
      error: 'unexpected_match_count',
      summary,
      expected: 380,
      actual: out.length
    }
  }];
}

return out;

const item = $json;
const html = item.data || '';

const ctx = $('Set Contexto').first().json;
const compSeason = $('Merge CompSeason ID').first().json || {};

function strip(s) {
  return (s || '')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&nbsp;/g, ' ')
    .replace(/&#160;/g, ' ')
    .replace(/&#8212;/g, '—')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalize(s) {
  return (s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

const seasonCompact =
  ctx.season_compact ||
  (ctx.season_label ? String(ctx.season_label).replace('/', '') : null);

if (!seasonCompact) {
  return [{ json: { error: 'missing_season_compact' } }];
}

const competitionId =
  compSeason.competition_id ||
  ctx.competition_id ||
  null;

const competitionSeasonId =
  compSeason.competition_season_id ||
  compSeason.id ||
  null;

// 1) localizar la tabla matriz Home \ Away
const tables = html.match(/<table[\s\S]*?<\/table>/gi) || [];

let matrixTable = null;
for (const table of tables) {
  const text = strip(table);
  if (/Home\s*\\\s*Away/i.test(text) || /Home\s*Away/i.test(text)) {
    // esta es la tabla cruzada de resultados
    matrixTable = table;
    break;
  }
}

if (!matrixTable) {
  return [{ json: { error: 'matrix_table_not_found' } }];
}

// 2) sacar filas
const rowMatches = [...matrixTable.matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)];
if (rowMatches.length < 3) {
  return [{ json: { error: 'matrix_rows_not_found' } }];
}

// helper para sacar celdas de una fila
function extractCells(rowHtml) {
  return [...rowHtml.matchAll(/<t[hd][^>]*>([\s\S]*?)<\/t[hd]>/gi)].map(m => strip(m[1]));
}

// 3) primera fila = cabecera con abreviaturas
const headerCells = extractCells(rowMatches[0][1]);

// Esperamos algo como: ["Home \\ Away", "ALA", "ATH", ...]
if (headerCells.length < 5) {
  return [{ json: { error: 'matrix_header_invalid', debug_header: headerCells } }];
}

const awayAbbrevs = headerCells.slice(1);

// 4) resto de filas = equipos locales + marcadores
const rawRows = rowMatches.slice(1).map(r => extractCells(r[1]));

// Nos quedamos con filas que realmente parecen de equipos
const teamRows = rawRows.filter(r => r.length >= 5);

// 5) construir mapa columna -> equipo usando el nombre de la fila
// La tabla está ordenada igual en cabecera y filas
const rowTeamNames = teamRows.map(r => r[0]);

if (rowTeamNames.length !== awayAbbrevs.length) {
  return [{
    json: {
      error: 'matrix_dimension_mismatch',
      awayAbbrevsCount: awayAbbrevs.length,
      rowTeamNamesCount: rowTeamNames.length
    }
  }];
}

// 6) parsear todos los cruces
const out = [];
const seen = new Set();

for (let i = 0; i < teamRows.length; i++) {
  const row = teamRows[i];
  const homeTeamRaw = row[0];
  const scoreCells = row.slice(1);

  for (let j = 0; j < scoreCells.length; j++) {
    const cell = scoreCells[j];
    const awayTeamRaw = rowTeamNames[j];

    // diagonal o vacío
    if (!cell || cell === '—' || normalize(homeTeamRaw) === normalize(awayTeamRaw)) {
      continue;
    }

    const scoreMatch = cell.match(/\b(\d+)[–-](\d+)\b/);
    if (!scoreMatch) continue;

    const homeScore = parseInt(scoreMatch[1], 10);
    const awayScore = parseInt(scoreMatch[2], 10);

    // En esta matriz no suele venir fecha; la añadiremos luego si hace falta en otra fase
    // De momento construimos el partido sin fecha exacta
    const sourceId = `laliga_${seasonCompact}_${normalize(homeTeamRaw)}_${normalize(awayTeamRaw)}_${homeScore}_${awayScore}`;

    if (seen.has(sourceId)) continue;
    seen.add(sourceId);

    out.push({
      competition_id: competitionId,
      competition_season_id: competitionSeasonId,
      home_team_raw: homeTeamRaw,
      away_team_raw: awayTeamRaw,
      match_date: null,
      home_score: homeScore,
      away_score: awayScore,
      status: 'finished',
      stage: 'league',
      source: 'wikipedia',
      source_id: sourceId,
      season: ctx.season_label ?? null,
      season_slug: ctx.season_slug ?? null,
    });
  }
}

if (!out.length) {
  return [{ json: { error: 'no_matches_parsed_from_matrix' } }];
}

return out.map(m => ({ json: m }));

