const ctx = $input.first().json;
const total = ctx.total_matchdays || 38;

const items = [];

for (let round = 1; round <= total; round++) {
  items.push({
    json: {
      ...ctx,
      round,
      transfermarkt_url: `${ctx.transfermarkt_base_url}/spieltag/${round}/saison_id/${ctx.transfermarkt_saison_id}`,
    }
  });
}

return items;

const inputItems = $input.all();
const output = [];

function stripHtml(s) {
  return (s || '')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#160;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseDate(raw) {
  if (!raw) return null;
  const m = raw.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (!m) return null;
  const dd = m[1].padStart(2, '0');
  const mm = m[2].padStart(2, '0');
  const yyyy = m[3];
  return `${yyyy}-${mm}-${dd}`;
}

function parseTime(raw) {
  if (!raw) return null;
  const m = raw.match(/\b(\d{1,2}):(\d{2})H?\b/);
  if (!m) return null;
  return `${m[1].padStart(2, '0')}:${m[2]}`;
}

function compactSlug(s) {
  return (s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

function cleanTeamTitles(titles) {
  const bad = new Set([
    'informe',
    'al hilo de la jornada',
    'al predictor de resultados',
    'transfermarkt',
  ]);

  return titles.filter(t => {
    const v = (t || '').toLowerCase().trim();
    return v && !bad.has(v);
  });
}

for (const wrapped of inputItems) {
  const item = wrapped.json;
  const html = item.data || '';

  const title = html.match(/<title>(.*?)<\/title>/i)?.[1] || '';
  const round =
    parseInt(title.match(/Jornada\s*-\s*(\d+)\./i)?.[1], 10) ||
    parseInt(title.match(/(\d+)\.\s*Jornada/i)?.[1], 10) ||
    item.round ||
    null;

  const season_label = item.season_label || null;
  const season_slug = item.season_slug || null;
  const competition_id = item.competition_id || null;
  const competition_season_id = item.competition_season_id || null;
  const transfermarkt_url = item.transfermarkt_url || null;

  const trs = html.match(/<tr[\s\S]*?<\/tr>/gi) || [];
  const seen = new Set();
  let foundForThisPage = 0;

  for (let i = 0; i < trs.length - 1; i++) {
    const tr1 = trs[i];
    const tr2 = trs[i + 1];

    const text1 = stripHtml(tr1);
    const text2 = stripHtml(tr2);

    const scoreMatch = text1.match(/(\d+):(\d+)/);
    if (!scoreMatch) continue;

    const dateMatch = text2.match(/\b\d{1,2}\/\d{1,2}\/\d{4}\b/);
    const timeMatch = text2.match(/\b\d{1,2}:\d{2}H?\b/);
    if (!dateMatch || !timeMatch) continue;

    const titlesRaw = [...tr1.matchAll(/title="([^"]+)"/gi)]
      .map(m => stripHtml(m[1]))
      .filter(Boolean);

    const titles = cleanTeamTitles(titlesRaw);
    if (titles.length < 2) continue;

    const home_team_raw = titles[0];
    const away_team_raw = titles[titles.length - 1];

    if (!home_team_raw || !away_team_raw) continue;
    if (home_team_raw === away_team_raw) continue;

    const match_date = parseDate(dateMatch[0]);
    const kickoff_time = parseTime(timeMatch[0]);
    if (!match_date || !kickoff_time) continue;

    const home_score = parseInt(scoreMatch[1], 10);
    const away_score = parseInt(scoreMatch[2], 10);

    const key = `${round}_${match_date}_${compactSlug(home_team_raw)}_${compactSlug(away_team_raw)}`;
    if (seen.has(key)) continue;
    seen.add(key);

    foundForThisPage++;

    output.push({
      json: {
        competition_id,
        competition_season_id,
        season: season_label,
        season_slug,
        round,
        match_date,
        kickoff_time,
        home_team_raw,
        away_team_raw,
        home_score,
        away_score,
        transfermarkt_url,
        source: 'transfermarkt',
        _match_key: `${match_date}_${compactSlug(home_team_raw)}_${compactSlug(away_team_raw)}`
      }
    });
  }

  if (!foundForThisPage) {
    output.push({
      json: {
        error: 'no_transfermarkt_matches_found',
        round,
        title,
        transfermarkt_url
      }
    });
  }
}

return output;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
